parameters.jsCode:
const candidates = [$json.sessionId, $json.conversationSessionId, $json.mcpSessionId];
const existing = candidates.find((value) => typeof value === 'string' && value.trim().length > 0) ?? null;
const payload = { ...$json };
if (existing) {
  const sessionId = existing.trim();
  payload.sessionId = sessionId;
  payload.conversationSessionId = sessionId;
}
return { json: payload };

const existingSessionId = typeof $json.sessionId === 'string' && $json.sessionId.trim().length > 0 ? $json.sessionId.trim() : null;
const rawOutput = $json.output ?? $json.result ?? $json;
let content = typeof rawOutput === 'string' ? rawOutput : JSON.stringify(rawOutput, null, 2);
if (!content || content.trim().length === 0) {
  content = JSON.stringify($json, null, 2);
}
const normalized = content.length > 4000 ? `${content.slice(0, 3997)}…` : content;
const metadata = {
  personaId: $json.personaId ?? null,
  projectId: $json.projectId ?? null,
  chatInput: $json.chatInput ?? null,
  workflow: $json.workflow ?? 'mylo-mcp-bot',
  outputSchema: $json.outputSchema ?? null,
};
const args = {
  role: 'assistant',
  content: normalized,
  metadata,
  tags: ['agent-response', 'mylo-mcp-bot'],
};
if (existingSessionId) {
  args.sessionId = existingSessionId;
}
const requestId = `store-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
return {
  json: {
    ...$json,
    conversationStoreRequest: {
      jsonrpc: '2.0',
      id: requestId,
      method: 'tools/call',
      params: {
        name: 'conversation_store',
        arguments: args,
      },
    },
  },
};
